import{_ as o,o as a,c as t,a2 as i}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"ADR-050 — Tiangong Explorer low-end fallback (?view=list + heuristics)","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-050.md","filePath":"adr/ADR-050.md"}'),r={name:"adr/ADR-050.md"};function n(s,e,d,l,c,h){return a(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-050-—-tiangong-explorer-low-end-fallback-view-list-heuristics" tabindex="-1">ADR-050 — Tiangong Explorer low-end fallback (<code>?view=list</code> + heuristics) <a class="header-anchor" href="#adr-050-—-tiangong-explorer-low-end-fallback-view-list-heuristics" aria-label="Permalink to &quot;ADR-050 — Tiangong Explorer low-end fallback (`?view=list` + heuristics)&quot;">​</a></h1><blockquote><p>Status · Accepted Date · 2026-05-07 Closes · RFC-014 (with ADR-048, ADR-049) TA anchor · §components Related · ADR-042 (the ISS analogue, copied verbatim), ADR-025 (accessibility), PRD-011</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>RFC-014 OQ-3 requires a non-WebGL path and automatic degradation on weak devices for <code>/tiangong</code>. The decision mirrors ADR-042 verbatim — same detection rules, same URL override, same single-reactive-<code>viewMode</code> UX.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="url-override" tabindex="-1">URL override <a class="header-anchor" href="#url-override" aria-label="Permalink to &quot;URL override&quot;">​</a></h3><p><strong><code>?view=list</code></strong> forces <strong>list mode</strong>: alphabetical module + visitor list, same <code>src/lib/components/StationModulePanel.svelte</code> content (the renamed/generalised panel — see Phase E of the rollout plan). <strong>No WebGL</strong> initialisation — no <code>THREE.WebGLRenderer</code>, no proxy build.</p><h3 id="auto-fallback" tabindex="-1">Auto-fallback <a class="header-anchor" href="#auto-fallback" aria-label="Permalink to &quot;Auto-fallback&quot;">​</a></h3><p>After 3D mode starts, measure FPS for <strong>~2 s</strong> via <code>requestAnimationFrame</code> deltas. If <strong>sustained &lt; 20 fps</strong>, switch to list mode and <strong>dispose</strong> renderer, scene, and module group geometry.</p><p>If <strong><code>navigator.deviceMemory</code></strong> is defined and <strong>&lt; 4</strong>, skip 3D and open in list mode immediately (Chrome/Android hint).</p><p>If <strong>WebGL context creation fails</strong>, list mode.</p><h3 id="ux" tabindex="-1">UX <a class="header-anchor" href="#ux" aria-label="Permalink to &quot;UX&quot;">​</a></h3><p>Single reactive <code>viewMode: &#39;3d&#39; | &#39;list&#39;</code> — same flicker-avoidance discipline as <code>/iss</code>: decide mode <strong>before</strong> first paint when URL/device hints demand list, otherwise fall through to 3D.</p><h3 id="toggle" tabindex="-1">Toggle <a class="header-anchor" href="#toggle" aria-label="Permalink to &quot;Toggle&quot;">​</a></h3><p>HUD control syncs URL (<code>view</code> search param) so shareable links reproduce mode.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong> Accessibility + low-end coverage without maintaining two full feature sets. Identical fallback contract across <code>/iss</code> and <code>/tiangong</code> reduces test surface.</p><p><strong>Negative:</strong> <code>navigator.deviceMemory</code> is non-standard — treated as optional signal only.</p><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><p>FPS sampler runs only when <code>viewMode === &#39;3d&#39;</code> after <code>buildTiangongProxyStation()</code> returns. Disposal path mirrors the ISS <code>stopThree()</code> helper.</p>',20)])])}const g=o(r,[["render",n]]);export{u as __pageData,g as default};
